C       SMPGe.for              SMPG Version 0.4                   5/7/92C	dFile generator: 3DOF prescriptionsC	Segmented Mirror Prescription GeneratorC	By:      David Redding, CS Draper Lab at the Jet Propulsion LabC	Address: JPL 185, 4800 Oak Grove Dr., Pasadena CA 91109C	Email:	 dcr@csi.jpl.nasa.gov, or dave@huey.jpl.nasa.govC	Phone:   (818)354-3696C  Declarations	IMPLICIT NONEC    The main sizing variables are set according to the maximum number C    of rings of the segmented array (mRing). In particular:C	   mR2 = 2 x mRingC	  mSeg = 3 x (mRing + 1) x mRing + 1C    Other arrays are set according to the number of measurements mMeasC	mState = 6 x mSegC	 mMeas = 6 x mSeg	INTEGER mRing,mR2,mSeg,mState,mMeas	PARAMETER (mRing=8, mR2=(2*mRing),      &	mSeg=(3*(mRing+1)*mRing+1), mMeas=(6*mSeg), mState=(6*mSeg))	INTEGER nRing,nElt,SegCoord(3,mSeg),iFirst,iLast,     &  SegCrdToNum(-mR2:mR2,-mR2:mR2),NumToRing(0:mSeg),     &	MeasToSeg(2,mMeas),iMeasConfig,iDOF	REAL*8 NumToPos(3,mSeg),NumToRadius(mSeg),pSeg(3,mSeg),     &	TbSeg(3,3,mSeg)	CHARACTER*8 Cinteger	INTEGER i,j,k,ip3,jp3,iRay,iElt,iEm1,iSeg,iRing,iLeg,jSeg,nR2,     &	iAdj,iMeas,nMeas,nState,iEltPrt,iPrt	REAL*8 radhat(3),tanhat(3),normhat(3),SegSize,MirApDiam,width,     &	length,w2,L2,S2,Pz(3,3),dpin(3),pinij(3),dzddeli(3),dzddelj(3),     &	dzdthi(3),dzdthj(3),zij(3),rhoi(3),rhoj(3),rhoix(3,3),dzdxi(6),     &	dzdxj(6),xhat(3),yhat(3),zhat(3),xseg(3)	REAL*8 pv(3),prot(3),pin(3),ihat(3),f,e,psi(3),     &  pr(3),rhat(3),L,rho(3),th,PI,ds,rs,qs,ps,ths,D1(100),D2(100),     &  D3(3,3),D4(3,3),S1,DOT,MAG,TElt(6,6),xSi,xSim1,ySi,ySim1,     &  dx,dy,twodx,SIN60,COS60,Hw1(6),Hw2(6)C  Formats 500	FORMAT(1P,'    iElt= ',i4/' EltName=  Seg',A/' EltType=  5'/     &	'    fElt= ',d17.9/'    eElt= ',d17.9/'  psiElt= ',3d17.9/     &	'  VptElt= ',3d17.9/'  RptElt= ',3d17.9/'  IndRef=  1d0'/     &	'    zElt= ',d17.9/'PropType= 1'/' nECoord=',i2) 501	FORMAT(1P,'    TElt= ',6d17.9) 502	FORMAT(1P,10x,6d17.9) 503	FORMAT(//'SegCoord= ',i5,2(5x,i5)) 504	FORMAT(10x,i5,2(5x,i5)) 505	FORMAT(/' Default mirror aperture diameter is ',1P,d17.9) 506	FORMAT(//' COMP Segmented Mirror Prescription Generator'/     &	' Version 0.4, May 7, 1992'//) 507	FORMAT(/'Default segment size is ',1P,d17.9) 508	FORMAT(/' nMeas=',i6,';'/' nState=',i6,';'/) 509	FORMAT(' Hx(',i6,',',i6,':',i6,')=[',6d17.9,'];') 512	FORMAT(' Hx(',i6,',',i6,':',i6,')=[',3d17.9,'];') 511	FORMAT(' Hw(',i6,',',i6,':',i6,')=[',6d17.9,'];') 510	FORMAT(' MeasToSeg(1:2,',i6,')=[',i6,';',i6,'];') 901	format('   iSeg=',i4,' jSeg=',i4/1P,'     pi=',3d17.9/     &	'     pj=',3d17.9/'     pr=',3d17.9/'   rhoi=',3d17.9/     &	'   rhoj=',3d17.9/'dzddeli=',3d17.9/'dzddelj=',3d17.9/     &	' dzdthi=',3d17.9/' dzdthj=',3d17.9/)C  Constants	DATA PI/3.141592653589793/SIN60/8.660254037844386d-01/	DATA COS60/0.5d0/C  Initialize arrays	CALL ZERO(Pz,9)	Pz(1,1)=1d0	Pz(2,2)=1d0	DO 8 j=-mR2,mR2	  DO 7 i=-mR2,mR2	    SegCrdToNum(i,j)=0  7	  CONTINUE  8	CONTINUEC  Set up data file	WRITE(*,506)	CALL SetOutFileC  Dialog for parameters of base mirror	CALL IACCEPT(iDOF,3,1,'Enter number of segment DOFs (3 or 6):')	IF (iDOF.NE.3) iDOF=6	CALL IACCEPT(iEltPrt,1,1,'Enter starting segment number:')	CALL IACCEPT(nRing,1,1,'Enter number of rings:')	CALL ZERO(pv,3)	CALL ZERO(prot,3)	D1(1)=0d0	D1(2)=0d0	D1(3)=1d0	CALL DACCEPT(psi,D1,3,     &	'Enter mirror principal axis direction (x,y,z):')	ihat(1)=-psi(1)	ihat(2)=-psi(2)	ihat(3)=-psi(3)c	f=1.46d0	S1=18d0	CALL DACCEPT(f,S1,1,'Enter mirror focal length:')	S1=1d0	CALL DACCEPT(e,S1,1,'Enter mirror eccentricity:')	CALL IACCEPT(iMeasConfig,1,1,     &	'Enter measurement configuration (1=inner, 2=all):')C  Enter mirror size parameters 21	CONTINUE	CALL IACCEPT(i,1,1,     &	'Enter size option (1=spec seg size, 2=spec aperture diam):')	IF (i.EQ.1) THEN	  S1=.03d0	  CALL DACCEPT(SegSize,S1,1,     &	  'Enter segment size (side-to-side):')	  width=SegSize	  length=SegSize/DCOS(PI/6d0)	  w2=width/2d0	  L2=length/2d0	  S2=length/4d0	  dx=w2	  dy=L2+S2	  twodx=width	  IF (nRing.EQ.0) THEN	    MirApDiam=length	  ELSEc	    MirApDiam=DSQRT((FLOAT(2*nRing+1)*width)**2+(S2*S2/4d0))	    MirApDiam=FLOAT(2*nRing+1)*width	  END IF	ELSE IF (i.EQ.2) THEN	  S1=12d0	  CALL DACCEPT(MirApDiam,S1,1,     &	  'Enter mirror aperture diameter:')	  SegSize=MirApDiam/FLOAT(2*nRing+1)	  width=SegSize	  length=SegSize/DCOS(PI/6d0)	  w2=width/2d0	  L2=length/2d0	  S2=length/4d0	  dx=w2	  dy=L2+S2	  twodx=width	ELSE	  WRITE(*,*) 'Invalid option...'	  GO TO 21	END IFC  Compute segment coordinates 	iElt=0	iPrt=iEltPrt-1	jSeg=0	SegCrdToNum(0,0)=1	NumToRing(0)=36000	xseg(3)=0d0	DO 4 iRing=0,nRing	  iFirst=1	  IF (iRing.EQ.0) THEN	    iLast=1	  ELSE	    iLast=iRing*6	  END IF	  DO 3 iSeg=iFirst,iLast	    iEm1=iElt	    iElt=iElt+1	    iPrt=iPrt+1	    jSeg=jSeg+1	    IF (iSeg.EQ.iFirst) THENC - First segment in ring is rightmost on top leg	      iLeg=5	      xseg(1)=SIN60	      xseg(2)=COS60	      pin(1)=0d0+dx*iRing	      pin(2)=0d0+dy*iRing	      pin(3)=100d0	      SegCoord(1,iElt)=iRing	      SegCoord(2,iElt)=2*iRing	      SegCoord(3,iElt)=iRing	    ELSE 	      iLeg=INT((iSeg-2)/iRing)	      IF ((iLeg.EQ.0).OR.(iLeg.EQ.6)) THENC - Top leg	        pin(1)=pin(1)-twodx	        xseg(1)=0d0	        xseg(2)=1d0	        SegCoord(1,iElt)=SegCoord(1,iEm1)-2	        SegCoord(2,iElt)=SegCoord(2,iEm1)-1	        SegCoord(3,iElt)=SegCoord(3,iEm1)+1	      ELSE IF (iLeg.EQ.1) THENC - Upper left leg	        xseg(1)=-SIN60	        xseg(2)=COS60	        pin(1)=pin(1)-dx	        pin(2)=pin(2)-dy	        SegCoord(1,iElt)=SegCoord(1,iEm1)-1	        SegCoord(2,iElt)=SegCoord(2,iEm1)-2	        SegCoord(3,iElt)=SegCoord(3,iEm1)-1	      ELSE IF (iLeg.EQ.2) THENC - Lower left leg	        xseg(1)=-SIN60	        xseg(2)=-COS60	        pin(1)=pin(1)+dx	        pin(2)=pin(2)-dy	        SegCoord(1,iElt)=SegCoord(1,iEm1)+1	        SegCoord(2,iElt)=SegCoord(2,iEm1)-1	        SegCoord(3,iElt)=SegCoord(3,iEm1)-2	      ELSE IF (iLeg.EQ.3) THENC - Bottom leg	        xseg(1)=0d0	        xseg(2)=-1d0	        pin(1)=pin(1)+twodx	        SegCoord(1,iElt)=SegCoord(1,iEm1)+2	        SegCoord(2,iElt)=SegCoord(2,iEm1)+1	        SegCoord(3,iElt)=SegCoord(3,iEm1)-1	      ELSE IF (iLeg.EQ.4) THENC - Lower right leg	        xseg(1)=SIN60	        xseg(2)=-COS60	        pin(1)=pin(1)+dx	        pin(2)=pin(2)+dy	        SegCoord(1,iElt)=SegCoord(1,iEm1)+1	        SegCoord(2,iElt)=SegCoord(2,iEm1)+2	        SegCoord(3,iElt)=SegCoord(3,iEm1)+1	      ELSE IF (iLeg.EQ.5) THENC - Upper right leg	        xseg(1)=SIN60	        xseg(2)=COS60	        pin(1)=pin(1)-dx	        pin(2)=pin(2)+dy	        SegCoord(1,iElt)=SegCoord(1,iEm1)-1	        SegCoord(2,iElt)=SegCoord(2,iEm1)+1	        SegCoord(3,iElt)=SegCoord(3,iEm1)+2	      END IF	    END IF	    NumToRing(iElt)=iRing	    SegCrdToNum(SegCoord(1,iElt),SegCoord(2,iElt))=iEltC - Find surface normal and local coordinates 	    CALL SurfCoord(rho,pr,L,radhat,tanhat,normhat,     &	    xhat,yhat,zhat,pv,prot,pin,ihat,f,e,psi,xseg)	    CALL EQUATE(pSeg(1,iElt),pr,3)	    CALL ZERO(TElt,36)	    DO 1 i=1,3	      j=i+3	      TElt(i,1)=xhat(i)	      TElt(i,2)=yhat(i)	      IF (iDOF.EQ.3) THEN	        TElt(j,3)=zhat(i)	      ELSE	        TElt(i,3)=zhat(i)	        TElt(j,4)=xhat(i)	        TElt(j,5)=yhat(i)	        TElt(j,6)=zhat(i)	      END IF	      TbSeg(i,1,iElt)=xhat(i)	      TbSeg(i,2,iElt)=yhat(i)	      TbSeg(i,3,iElt)=zhat(i)  1	    CONTINUE	    CALL IntToChar(Cinteger,jSeg,i)	    WRITE(2,500)iPrt,Cinteger(1:i),f,e,psi,pv,pr,f,iDOF	    WRITE(2,501)(TElt(1,j),j=1,iDOF)	    DO 2 i=2,6	      WRITE(2,502)(TElt(i,j),j=1,iDOF)  2	    CONTINUE  3	  CONTINUE  4	CONTINUE	nElt=iElt	WRITE(9,503)(SegCoord(i,1),i=1,3)	WRITE(2,503)(SegCoord(i,1),i=1,3)	DO 5 iElt=2,nElt	  WRITE(9,504)(SegCoord(i,iElt),i=1,3)	  WRITE(2,504)(SegCoord(i,iElt),i=1,3)  5	CONTINUEC  Compute edge-sensor measurement matricesC    First measurement is of master segment absolute piston	iMeas=1	CALL ZERO(dzdxi,6)	dzdxi(6)=1d0	IF (iDOF.EQ.3) THEN	  WRITE(3,512)iMeas,1,iDOF,dzdxi(1),dzdxi(2),dzdxi(6)	ELSE	  WRITE(3,509)iMeas,1,iDOF,dzdxi	END IF	MeasToSeg(1,iMeas)=1	MeasToSeg(2,iMeas)=1C    Loop through each segment		DO 20 iElt=2,nElt	  iSeg=iElt	  iRing=NumToRing(iElt)	  DO 19 iAdj=1,6C    Find each adjacent segment	    IF (iAdj.EQ.1) THEN	      i=SegCoord(1,iElt)+1	      j=SegCoord(2,iElt)+2	    ELSE IF (iAdj.EQ.2) THEN	      i=SegCoord(1,iElt)-1	      j=SegCoord(2,iElt)+1	    ELSE IF (iAdj.EQ.3) THEN	      i=SegCoord(1,iElt)-2	      j=SegCoord(2,iElt)-1	    ELSE IF (iAdj.EQ.4) THEN	      i=SegCoord(1,iElt)-1	      j=SegCoord(2,iElt)-2	    ELSE IF (iAdj.EQ.5) THEN	      i=SegCoord(1,iElt)+1	      j=SegCoord(2,iElt)-1	    ELSE IF (iAdj.EQ.6) THEN	      i=SegCoord(1,iElt)+2	      j=SegCoord(2,iElt)+1	    END IF	    IF ((ABS(i).LE.MR2).AND.(ABS(j).LE.MR2)) THEN	      jSeg=SegCrdToNum(i,j)	    ELSE	      jSeg=0	    END IFC   If adjacent segment exists and is eligible, compute Hx submatrix	    IF ((jSeg.GT.0).AND.     &	    (((iMeasConfig.EQ.1).AND.(NumToRing(jSeg).LE.iRing))     &	    .OR.(iMeasConfig.EQ.2)))THEN	      CALL SUB(D1,pSeg(1,jSeg),pSeg(1,iSeg),3)	      CALL MPROD(D2,Pz,D1,3,3,1)	      CALL SMPROD(dpin,D2,5d-1,3)	      CALL MPROD(D1,Pz,pSeg(1,iSeg),3,3,1)	      CALL ADD(pin,D1,dpin,3)	      pin(3)=100d0	      CALL SurfCoord(rho,pr,L,radhat,tanhat,normhat,     &	      xhat,yhat,zhat,pv,prot,pin,ihat,f,e,psi,xseg)	      CALL SUB(rhoi,pr,pSeg(1,iSeg),3)	      CALL SUB(rhoj,pr,pSeg(1,jSeg),3)	      CALL MPROD(dzddeli,normhat,TbSeg(1,1,iSeg),1,3,3)	      CALL MPROD(D1,normhat,TbSeg(1,1,jSeg),1,3,3)	      CALL NEGATE(dzddelj,D1,3)	      CALL CROSSMAT(rhoix,rhoi)	      CALL MPROD(D1,normhat,TbSeg(1,1,iSeg),1,3,3)	      CALL MPROD(D2,D1,rhoix,1,3,3)	      CALL NEGATE(dzdthi,D2,3)	      CALL MPROD(D1,normhat,TbSeg(1,1,jSeg),1,3,3)	      CALL MPROD(dzdthj,D1,rhoix,1,3,3)	      CALL EQUATE(dzdxi,dzdthi,3)	      CALL EQUATE(dzdxi(4),dzddeli,3)	      CALL EQUATE(dzdxj,dzdthj,3)	      CALL EQUATE(dzdxj(4),dzddelj,3)	      iMeas=iMeas+1	      MeasToSeg(1,iMeas)=iSeg	      MeasToSeg(2,iMeas)=jSeg	      i=(iSeg-1)*iDOF+1	      k=iSeg*iDOFc	      WRITE(3,509)iMeas,i,k,dzdxi	      IF (iDOF.EQ.3) THEN	        WRITE(3,512)iMeas,i,k,dzdxi(1),dzdxi(2),dzdxi(6)	      ELSE	        WRITE(3,509)iMeas,i,k,dzdxi	      END IF	      j=(jSeg-1)*iDOF+1	      k=jSeg*iDOFc	      WRITE(3,509)iMeas,j,k,dzdxj	      IF (iDOF.EQ.3) THEN	        WRITE(3,512)iMeas,j,k,dzdxj(1),dzdxj(2),dzdxj(6)	      ELSE	        WRITE(3,509)iMeas,j,k,dzdxj	      END IF	    END IF 19	  CONTINUE 20	CONTINUE	nMeas=iMeas	nState=iDOF*nElt	WRITE(3,508)nMeas,nState	DO 10 iMeas=1,nMeas	  WRITE(3,510)iMeas,(MeasToSeg(i,iMeas),i=1,2) 10	CONTINUEC  End of program	CLOSE (2)	CLOSE (3)	WRITE(*,*) "Hit return to exit"	ACCEPT i	STOP	ENDC***********************************************************************	SUBROUTINE SurfCoord(rho,pr,L,radhat,tanhat,normhat,     &	xhat,yhat,zhat,pv,prot,pin,ihat,f,e,psi,xseg)C       Inputs are:C               pv = position of the vertex of the mirror in base	C		     coordinatesC             prot = position of the mirror rotation point in base	C		     coordinatesC              pin = position of the incident ray reference point in	C		     base coordinatesC	      ihat = direction of the incident rayC                f = distance between the vertex and focus of the mirrorC		 e = eccentricity of mirror (0=sphere, 0-1=ellipse,	C		     1=parabola, >1=hyperbola)C	       psi = mirror principal axis direction from vertex out	C		     concave sideC       Outputs are:C               pr = position of the reflection point in baseC		     coordinatesC                L = length of incident ray from previous reference pt	IMPLICIT NONE	REAL*8 pv(3),prot(3),pin(3),ihat(3),f,e,psi(3),     &  pr(3),rhat(3),L,Nhat(3),radhat(3),tanhat(3),normhat(3),     &	xhat(3),yhat(3),zhat(3),xseg(3)	REAL*8 prel(3),M(3,3),N0(3),a,b,c,ksqrt,kp,km,mpr,rho(3),     &  Nvec(3),Nmag,dNdp(3,3),R(3,3),dpdd(3,3),dNdd(3,3),dNdi(3,3),     &  Ndoti,Niinv,Nouti(3,3),drdN(3,3),drdd(3,3),drdth(3,3),drdi(3,3),     &  drda(3,3),dgda(3,3),dgdi(3,3),dgdd(3,3),dlddi(3,3),dldd(3),     &  dprot(3),dddth(3,3),dgdth(3,3),drdthttl(3,3),dldth(3),Kc,Kr,     &  NoidNdi(3,3)	REAL*8 D1(100),D2(100),D3(3,3),D4(3,3),S1,S2,DOT,MAG	INTEGER i,j,ip3,jp3,iRay,iElt,iEm1C	Compute mirror model	Kc=-e**2	Kr=-(1d0+e)*f	CALL SUB(prel,pin,pv,3)	IF (f.LE.1d8) THEN	  DO 2 i=1,3	    DO 1 j=1,3	      M(i,j)=Kc*psi(i)*psi(j)  1	    CONTINUE	    M(i,i)=M(i,i)+1d0	    N0(i)=Kr*psi(i)  2	  CONTINUE	  CALL MPROD(D1,M,ihat,3,3,1)	  a=DOT(ihat,D1)	  CALL MPROD(D1,M,prel,3,3,1)	  CALL ADD(D2,D1,N0,3)	  b=2d0*DOT(ihat,D2)	  CALL ADD(D1,D2,N0,3)	  c=DOT(prel,D1)	ELSE	  DO 4 i=1,3	    DO 3 j=1,3	      M(i,j)=0d0  3	    CONTINUE	    N0(i)=psi(i)  4	  CONTINUE	  a=0d0	  b=2d0*DOT(ihat,N0)	  c=2d0*DOT(prel,N0)	END IFC	Compute intersection point and normal vector	IF ((DABS(a).LE.1d-18).OR.(f.GE.1d9)) THEN	  L=-c/b	ELSE	  ksqrt=DSQRT(b**2-4d0*a*c);	  kp=(-2d0*c)/(b+ksqrt);	  km=(-2d0*c)/(b-ksqrt);	  mpr=MAG(prel,3);	  IF (DABS(DABS(kp)-mpr).LE.DABS(DABS(km)-mpr)) THEN	    L=kp;	  ELSE	    L=km;	  END IF	END IF	CALL SMPROD(D1,ihat,L,3)	CALL ADD(pr,pin,D1,3)	CALL ADD(rho,prel,D1,3)	CALL MPROD(D1,M,rho,3,3,1)	CALL ADD(Nvec,N0,D1,3)	CALL UNITVEC(D1,Nvec,Nmag,3)	S1=-DSIGN(1d0,DOT(Nvec,ihat))	CALL SMPROD(Nhat,D1,S1,3)	S1=1d0/Nmag	CALL PROJECT(D1,Nhat)	CALL MPROD(D2,D1,M,3,3,3)	CALL SMPROD(dNdp,D2,S1,9)C	Compute coordinates	S1=DOT(rho,rho)	IF (S1.LE.1D-16) THEN	  tanhat(1)=0d0	  tanhat(2)=1d0	  tanhat(3)=0d0	ELSE	  CALL CROSSPROD(tanhat,Nhat,rho)	END IF	CALL UNITIZE(tanhat)	CALL EQUATE(normhat,Nhat,3)	CALL CROSSPROD(radhat,tanhat,Nhat)	CALL UNITIZE(radhat)	S1=DOT(xseg,xseg)	IF (S1.LE.1D-16) THEN	  yhat(1)=0d0	  yhat(2)=1d0	  yhat(3)=0d0	ELSE	  CALL CROSSPROD(yhat,Nhat,xseg)	END IF	CALL UNITIZE(yhat)	CALL EQUATE(zhat,Nhat,3)	CALL CROSSPROD(xhat,yhat,Nhat)	CALL UNITIZE(xhat)	RETURN	ENDC	End of SurfCoordC***********************************************************************C***********************************************************************	SUBROUTINE SetOutFile	CHARACTER*32 ans,filnam,infil,outfil,Hxfil,Hwfil	LOGICAL exist	INTEGER i,j,k,l,iaxis,iElt,npts,iopt,iCoord,GridType,npp1,     &	inIvec(3)C	Get file name	DO	  iopt=0	  ANS="y"	  filnam = " "	  TYPE "Enter output file name: "	  ACCEPT filnam	  IF (filnam = " ") CYCLE	  l = len(trim(filnam))	  infil=filnam	  outfil=filnam	  Hxfil=filnam	  Hwfil=filnam	  infil(l+1:l+3) = ".in"	  outfil(l+1:l+4) = ".presc"	  Hxfil(l+1:l+4) = "Hx.m"	  Hwfil(l+1:l+4) = "Hw.m"	  INQUIRE (file=infil,exist=exist)	  IF (exist) THEN	    WRITE (9,*)      &      "Input file "//trim(outfil)//" exists.  Overwrite?"	    ACCEPT ans	    IF ((ans(1:1) = "y").OR.(ans(1:1) = "Y")) THEN	      iopt=1	    ELSE	      CYCLE	    END IF	  END IF	  EXIT	REPEAT	OPEN (2,FILE=TRIM(outfil),STATUS="NEW")  	OPEN (3,FILE=TRIM(Hxfil),STATUS="NEW")  c	OPEN (4,FILE=TRIM(HWfil),STATUS="NEW")  	RETURN	ENDC***********************************************************************C      SUBROUTINE ADD(A,B,C,N)      REAL*8 A(N),B(N),C(N)      DO 1 I=1,N    1 A(I)=B(I)+C(I)      RETURN      ENDC      SUBROUTINE SUB(A,B,C,N)      REAL*8 A(N),B(N),C(N)      DO 1 I=1,N    1 A(I)=B(I)-C(I)      RETURN      ENDC      SUBROUTINE SMPROD(A,B,S,N)      REAL*8 A(1),B(1),S      DO 1 I=1,N    1 A(I)=B(I)*S      RETURN      ENDC      SUBROUTINE NEGATE(A,B,N)      REAL*8 A(1),B(1)      DO 1 J=1,N    1 A(J)=-B(J)      RETURN      ENDC      SUBROUTINE EQUATE(A,B,N)      REAL*8 A(1),B(1)      DO 1 J=1,N    1 A(J)=B(J)      RETURN      ENDC      SUBROUTINE EQTsp(A,B,N)      REAL*4 A(1),B(1)      DO 1 J=1,N    1 A(J)=B(J)      RETURN      ENDCC      SUBROUTINE UNITVEC(YHAT,Y,MAG,N)      REAL*8 YHAT(1),Y(1),MAG      MAG=0D0      DO (I=1,N)	MAG=MAG+Y(I)**2      END DO      MAG=DSQRT(MAG)      DO (I=1,N)	YHAT(I)=Y(I)/MAG      END DO      RETURN      ENDC      FUNCTION MAG(X,N)      REAL*8 X(N),MAG      MAG=0D0      DO (I=1,N)        MAG=MAG+X(I)*X(I)      END DO      MAG=DSQRT(MAG)      RETURN      ENDC      FUNCTION DOT(X,Y)      REAL*8 X(3),Y(3),DOT      DOT=X(1)*Y(1)+X(2)*Y(2)+X(3)*Y(3)      RETURN      ENDC      SUBROUTINE UNITSP(X)      REAL*4 X(3),Y      Y=SQRT(X(1)*X(1)+X(2)*X(2)+X(3)*X(3))      IF (Y.GT.1D-10) THEN        X(1)=X(1)/Y        X(2)=X(2)/Y        X(3)=X(3)/Y      ELSE        X(1)=0D0        X(2)=0D0        X(3)=0D0      END IF      RETURN      ENDCC      SUBROUTINE UNITIZE(X)      REAL*8 X(3),Y      Y=SQRT(X(1)*X(1)+X(2)*X(2)+X(3)*X(3))      IF (Y.GT.1D-10) THEN        X(1)=X(1)/Y        X(2)=X(2)/Y        X(3)=X(3)/Y      ELSE        X(1)=0D0        X(2)=0D0        X(3)=0D0      END IF      RETURN      ENDC      FUNCTION RSS(X)      REAL*8 X(3),RSS      RSS=DSQRT(X(1)*X(1)+X(2)*X(2)+X(3)*X(3))      RETURN      ENDCC      SUBROUTINE MPROD(A,B,C,NA,NB,NC)      REAL*8 A(1),B(1),C(1)      NAMAX=NA*NC      NBMAX=NA*NB      DO 1 I=1,NA      J=-NB      DO 1 NAPTR=I,NAMAX,NA      J=J+NB      K=0      A(NAPTR)=0D0      DO 1 NBPTR=I,NBMAX,NA      K=K+1      NCPTR=J+K    1 A(NAPTR)=A(NAPTR)+B(NBPTR)*C(NCPTR)      RETURN      ENDCC      SUBROUTINE MPRODB(A,B,C,NA,NB,NC)      REAL*8 A(1),B(1),C(1),BIK      NAMAX=NA*NC      NBMAX=NA*NB      DO 1 NAPTR=1,NAMAX    1 A(NAPTR)=0D0      DO 3 I=1,NA      K=0      DO 3 NBPTR=I,NBMAX,NA      K=K+1      BIK=B(NBPTR)      IF (BIK.EQ.0D0) GO TO 3      NCPTR=K      DO 2 NAPTR=I,NAMAX,NA      A(NAPTR)=A(NAPTR)+BIK*C(NCPTR)    2 NCPTR=NCPTR+NB    3 CONTINUE      RETURN      ENDCC      SUBROUTINE MPBsp(A,B,C,NA,NB,NC)      REAL*4 A(1),B(1),C(1),BIK      NAMAX=NA*NC      NBMAX=NA*NB      DO 1 NAPTR=1,NAMAX    1 A(NAPTR)=0D0      DO 3 I=1,NA      K=0      DO 3 NBPTR=I,NBMAX,NA      K=K+1      BIK=B(NBPTR)      IF (BIK.EQ.0D0) GO TO 3      NCPTR=K      DO 2 NAPTR=I,NAMAX,NA      A(NAPTR)=A(NAPTR)+BIK*C(NCPTR)    2 NCPTR=NCPTR+NB    3 CONTINUE      RETURN      ENDCC      SUBROUTINE MPRODC(A,B,C,NA,NB,NC)      REAL*8 A(1),B(1),C(1),CJK      NAM1=NA-1      NAMAX=NA*NC      NCMAX=NB*NC      DO 1 NAPTR=1,NAMAX    1 A(NAPTR)=0D0      K=-NA      DO 3 J=1,NB      K=K+NA      I=-NAM1      DO 3 NCPTR=J,NCMAX,NB      I=I+NA      CJK=C(NCPTR)      IF (CJK.EQ.0D0) GO TO 3      II=I+NAM1      NBPTR=K      DO 2 NAPTR=I,II      NBPTR=NBPTR+1    2 A(NAPTR)=A(NAPTR)+B(NBPTR)*CJK    3 CONTINUE      RETURN      ENDCC      SUBROUTINE MPCsp(A,B,C,NA,NB,NC)      REAL*4 A(1),B(1),C(1),CJK      NAM1=NA-1      NAMAX=NA*NC      NCMAX=NB*NC      DO 1 NAPTR=1,NAMAX    1 A(NAPTR)=0D0      K=-NA      DO 3 J=1,NB      K=K+NA      I=-NAM1      DO 3 NCPTR=J,NCMAX,NB      I=I+NA      CJK=C(NCPTR)      IF (CJK.EQ.0D0) GO TO 3      II=I+NAM1      NBPTR=K      DO 2 NAPTR=I,II      NBPTR=NBPTR+1    2 A(NAPTR)=A(NAPTR)+B(NBPTR)*CJK    3 CONTINUE      RETURN      ENDCC      SUBROUTINE MPACsp(A,B,C,NA,NB,NC)      REAL*4 A(1),B(1),C(1),CJK      NAM1=NA-1      NAMAX=NA*NC      NCMAX=NB*NCc     DO 1 NAPTR=1,NAMAXc   1 A(NAPTR)=0D0      K=-NA      DO 3 J=1,NB      K=K+NA      I=-NAM1      DO 3 NCPTR=J,NCMAX,NB      I=I+NA      CJK=C(NCPTR)      IF (CJK.EQ.0D0) GO TO 3      II=I+NAM1      NBPTR=K      DO 2 NAPTR=I,II      NBPTR=NBPTR+1    2 A(NAPTR)=A(NAPTR)+B(NBPTR)*CJK    3 CONTINUE      RETURN      ENDCC      SUBROUTINE TRPOS(A,B,NA,NB)      REAL*8 A(NA,NB),B(NB,NA)      DO 1 I=1,NA      DO 1 J=1,NB    1 A(I,J)=B(J,I)      RETURN      ENDC      SUBROUTINE ZERO(A,N)      REAL*8 A(1)      DO 1 I=1,N    1 A(I)=0D0      RETURN      ENDC       SUBROUTINE MINV2(A1,A)       REAL*8 A1(2,2),A(2,2),DET       DET=A(1,1)*A(2,2)-A(2,1)*A(1,2)       A1(1,1)=A(2,2)/DET       A1(1,2)=-A(1,2)/DET       A1(2,1)=-A(2,1)/DET       A1(2,2)=A(1,1)/DET       RETURN       ENDC      SUBROUTINE MINV(AI,A,N)      IMPLICIT REAL*8 (A-H,O-Z)      DIMENSION A(N,N),AI(N,N),AX(5,10)      DO 2 I=1,N      DO 1 J=1,N      AX(I,J)=A(I,J)    1 AX(I,N+J)=0D0    2 AX(I,N+I)=1D0      NP=2*N      DO 7 I=1,N      ALFA=AX(I,I)      DO 3 J=1,NP    3 AX(I,J)=AX(I,J)/ALFA      DO 6 K=1,N      IF(K-I)4,6,4    4 BETA=AX(K,I)      DO 5 J=1,NP    5 AX(K,J)=AX(K,J)-BETA*AX(I,J)    6 CONTINUE    7 CONTINUE      DO 8 I=1,N      DO 8 J=1,N    8 AI(I,J)=AX(I,J+N)      RETURN      ENDCC	SUBROUTINE OUTER(X,Y,Z)	REAL*8 X(3,3),Y(3),Z(3)	DO (I = 1,3)	  DO (J = 1,3)	    X(I,J)=Y(I)*Z(J)	  END DO	END DO	RETURN	ENDC	SUBROUTINE REFLECT(R,N)	REAL*8 R(3,3),N(3),MAG        MAG=SQRT(N(1)*N(1)+N(2)*N(2)+N(3)*N(3))        N(1)=N(1)/MAG        N(2)=N(2)/MAG        N(3)=N(3)/MAG	R(1,1)=-2D0*N(1)*N(1)+1D0	R(1,2)=-2D0*N(1)*N(2)	R(1,3)=-2D0*N(1)*N(3)	R(2,1)=R(1,2)	R(2,2)=-2D0*N(2)*N(2)+1D0	R(2,3)=-2D0*N(2)*N(3)	R(3,1)=R(1,3)	R(3,2)=R(2,3)	R(3,3)=-2D0*N(3)*N(3)+1D0	RETURN	ENDCC      SUBROUTINE DTSP(A,B,NAROW,NACOL,NACAT)      REAL*4 A(NAROW,NACOL,NACAT)      REAL*8 B(NAROW,NACOL,NACAT)      DO 1 K=1,NACAT      DO 1 J=1,NACOL      DO 1 I=1,NAROW    1 A(I,J,K)=B(I,J,K)      RETURN      ENDCC      SUBROUTINE COMPACT(A,B,NAROW,NACOL,NBROW,NBCOL)      REAL*4 A(NAROW,NACOL)      REAL*8 B(NBROW,NBCOL)      DO 1 J=1,NACOL      DO 1 I=1,NAROW    1 A(I,J)=B(I,J)      RETURN      ENDC	SUBROUTINE PROJECT(P,N)	REAL*8 P(3,3),N(3),MAG        MAG=SQRT(N(1)*N(1)+N(2)*N(2)+N(3)*N(3))        N(1)=N(1)/MAG        N(2)=N(2)/MAG        N(3)=N(3)/MAG	P(1,1)=-N(1)*N(1)+1D0	P(1,2)=-N(1)*N(2)	P(1,3)=-N(1)*N(3)	P(2,1)=P(1,2)	P(2,2)=-N(2)*N(2)+1D0	P(2,3)=-N(2)*N(3)	P(3,1)=P(1,3)	P(3,2)=P(2,3)	P(3,3)=-N(3)*N(3)+1D0	RETURN	ENDC	SUBROUTINE CROSSMAT(X,Y)	REAL*8 X(3,3),Y(3)	X(1,1)=0D0	X(1,2)=-Y(3)	X(1,3)= Y(2)	X(2,1)= Y(3)	X(2,2)=0D0	X(2,3)=-Y(1)	X(3,1)=-Y(2)	X(3,2)= Y(1)	X(3,3)=0D0	RETURN	ENDC	SUBROUTINE CROSSPROD(X,Y,Z)	REAL*8 X(3),Y(3),Z(3)	X(1)=-Y(3)*Z(2)+Y(2)*Z(3)	X(2)= Y(3)*Z(1)-Y(1)*Z(3)	X(3)=-Y(2)*Z(1)+Y(1)*Z(2)	RETURN	ENDC***********************************************************************	SUBROUTINE DACCEPT(DVAR,DDEF,N,TEXT)C	DOUBLE-PRECISION N-VECTOR INPUT ROUTINE DACCEPTC	TYPES OUT TEXTC	IF INPUT IS CR, DVAR=DDEFC	OTHERWISE, DVAR=INPUT	CHARACTER*(*) TEXT	REAL*8 DVAR(N),DDEF(N)	CHARACTER*31 ASTR(9)  1	FORMAT(1X,A,'[',G23.16,'] ')  2	FORMAT(9A)  3	FORMAT(F31.0) 15	FORMAT(1X,A)100	TYPE(9,15)TEXT	DO 4 I=1,N	  ASTR(I)=' '  4	CONTINUE	ACCEPT (ASTR(I),I=1,N)	DO 5 I=1,N	  IF(ASTR(I).EQ.' ')THEN	    DVAR(I)=DDEF(I)	  ELSE	    READ(ASTR(I),3,ERR=100)DVAR(I)	  ENDIF  5	CONTINUE	RETURN	ENDC***********************************************************************	SUBROUTINE RACCEPT(RVAR,RDEF,N,TEXT)C	REAL*4 N-VECTOR INPUT ROUTINE DACCEPTC	TYPES OUT TEXTC	IF INPUT IS CR, RVAR=RDEFC	OTHERWISE, RVAR=INPUT	CHARACTER*(*) TEXT	REAL*4 RVAR(N),RDEF(N)	CHARACTER*31 ASTR(9)  1	FORMAT(1X,A,'[',G23.16,'] ')  2	FORMAT(9A)  3	FORMAT(F31.0) 15	FORMAT(1X,A)100	TYPE(9,15)TEXT	DO 4 I=1,N	  ASTR(I)=' '  4	CONTINUE	ACCEPT (ASTR(I),I=1,N)	DO 5 I=1,N	  IF(ASTR(I).EQ.' ')THEN	    RVAR(I)=RDEF(I)	  ELSE	    READ(ASTR(I),3,ERR=100)RVAR(I)	  ENDIF  5	CONTINUE	RETURN	ENDC***********************************************************************	SUBROUTINE IACCEPT(IVAR,IDEF,N,TEXT)C	INTEGER N-VECTOR INPUT ROUTINE IACCEPTC	TYPES OUT TEXTC	IF INPUT IS CR, IVAR=IDEFC	OTHERWISE, IVAR=INPUT	CHARACTER*(*) TEXT	INTEGER IVAR(N),IDEF(N)	CHARACTER*31 ASTR(9)  1	FORMAT(1X,A,'[',G23.16,'] ')  2	FORMAT(9A)  3	FORMAT(I31) 15	FORMAT(1X,A)100	TYPE(9,15)TEXT	DO 4 I=1,N	  ASTR(I)=' '  4	CONTINUE	ACCEPT (ASTR(I),I=1,N)	DO 5 I=1,N	  IF(ASTR(I).EQ.' ')THEN	    IVAR(I)=IDEF(I)	  ELSE	    READ(ASTR(I),3,ERR=100)IVAR(I)	  ENDIF  5	CONTINUE	RETURN	ENDC***********************************************************************	SUBROUTINE CACCEPT(CVAR,CDEF,TEXT)C	CHARACTER INPUT ROUTINE CACCEPTC	TYPES OUT TEXTC	IF INPUT IS CR, CVAR=CDEFC	OTHERWISE, IVAR=INPUT	CHARACTER*(*) TEXT,CDEF	CHARACTER*32 CVAR	CHARACTER*31 ASTR  1	FORMAT(1X,A,' (',A,'): ')  5	FORMAT(1X,A)100	CONTINUE	CVAR=' '	IF (CDEF.EQ.' ')THEN	  TYPE(9,5)TEXT	  ACCEPT CVAR		  IF(CVAR.EQ.' ')GO TO 100	ELSE	  TYPE(9,1)TEXT,CDEF	  ACCEPT CVAR		  IF(CVAR.EQ.' ')CVAR=CDEF	END IF	RETURN	ENDC***********************************************************************	SUBROUTINE PROMPT(CVAR,TEXT)	CHARACTER*(*) TEXT	CHARACTER*32 CVAR  5	FORMAT(1X,A)100	CONTINUE	CVAR=' '	TYPE(9,5)TEXT	ACCEPT CVAR		IF(CVAR.EQ.' ')GO TO 100	RETURN	ENDC***********************************************************************	SUBROUTINE IntToChar(Char,Int,len)	IMPLICIT NONE	CHARACTER*8 C1	CHARACTER*8 Char	INTEGER i,l,nend,nstart,len,Int 1	FORMAT(i8)	WRITE(C1,1)Int	i=0 2      CONTINUE	  i=i+1	  iF ((C1(i:i).EQ.' ').AND.(i.LT.8)) GO TO 2	nstart=ic 3      CONTINUEc	  i=i+1c	  iF ((C1(i:i).NE.' ').AND.(i.LE.8)) GO TO 3c	nend=i-1	nend=8	Char=c1(nstart:nend)	len=nend-nstart+1	RETURN	ENDC***********************************************************************